import React, { useContext } from 'react';
import { CheckCircle2, XCircle, Share2 } from 'lucide-react';
import { useCurrency } from '../context/CurrencyContext';

/**
 * TransactionResultScreen Component
 * Shows whether a transaction succeeded or failed.
 */
const TransactionResultScreen = ({ status = 'success', amount, type, onDone }) => {
  const isSuccess = status === 'success';
  const { currencySymbol } = useCurrency(); // 🔹 Get current currency

  return (
    <div className={`h-full flex flex-col p-8 animate-in ${isSuccess ? 'bg-white' : 'bg-red-50'}`}>

      <div className="flex-1 flex flex-col items-center justify-center">
        <div className={`w-24 h-24 rounded-[2.5rem] flex items-center justify-center mb-6 
          ${isSuccess ? 'bg-emerald-50 text-[#00875A]' : 'bg-white text-red-500 shadow-xl'}`}>
          {isSuccess ? <CheckCircle2 size={48} strokeWidth={2.5} /> : <XCircle size={48} strokeWidth={2.5} />}
        </div>

        <h2 className="text-3xl font-black text-gray-900 mb-2">
          {isSuccess ? 'Payment Successful' : 'Transaction Failed'}
        </h2>

        <p className="text-gray-400 font-bold text-center mb-8">
          {isSuccess 
            ? `Your ${type} of ${currencySymbol}${amount} has been processed.` 
            : 'Your bank declined the request. Please check your balance and try again.'}
        </p>

        {isSuccess && (
          <div className="w-full bg-gray-50 rounded-[2rem] p-6 space-y-4">
            <div className="flex justify-between">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Reference</span>
              <span className="font-mono text-xs font-bold">NEST-TX-928374</span>
            </div>
            <div className="flex justify-between border-t border-gray-100 pt-4">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Total Amount</span>
              <span className="font-black text-gray-900">{currencySymbol}{amount}</span>
            </div>
          </div>
        )}
      </div>

      <div className="space-y-3">
        {isSuccess && (
          <button className="w-full py-4 rounded-2xl border-2 border-gray-100 font-black text-gray-800 flex items-center justify-center gap-2 active:scale-95 transition-all">
            <Share2 size={18} /> Share Receipt
          </button>
        )}
        <button 
          onClick={onDone}
          className={`w-full py-5 rounded-[2rem] font-black text-white active:scale-95 transition-all ${isSuccess ? 'bg-[#00875A] shadow-xl shadow-emerald-100' : 'bg-gray-900'}`}
        >
          {isSuccess ? 'Back to Home' : 'Try Another Method'}
        </button>
      </div>
    </div>
  );
};

export default TransactionResultScreen;
